{
  "options": [
    {
      "text": "按住德索洛的肩膀，让他先深呼吸，再问清楚凯旋门对他女儿做了什么",
      "actionId": "choice:推进节点02-02：让德索洛详细陈述女儿遭遇"
    },
    {
      "text": "转向卡琳娜，低声问她：“你打算怎么处理？”",
      "actionId": "choice:推进节点02-02：询问卡琳娜的意向"
    },
    {
      "text": "沉默。让德索洛自己说下去，看他还有多少脸开口",
      "actionId": "choice:推进节点02-02：保持沉默观察德索洛"
    }
  ]
}
